import { useEffect, useRef, useState } from "react";
import {useSharedValue} from "react-native-reanimated";

interface UseFormInputControllerProps<T> {
    value?: T;
    defaultValue?: T;
    onChange?: (event: { target: { value: T } }) => void;
}

export function useFormInputController<T>({
                                value,
                                defaultValue,
                                onChange,
                            }: UseFormInputControllerProps<T>) {
    const isControlled = value !== undefined;


    const currentReanimatedValue = useSharedValue(defaultValue);

    const [internalValue, setInternalValue] = useState<T | undefined>(
        defaultValue
    );

    // keep ref to avoid stale closures
    const latestValueRef = useRef(value);
    latestValueRef.current = value;

    // sync ONLY when switching to controlled
    useEffect(() => {
        if (isControlled) {
            setInternalValue(value);
        }
    }, [isControlled, value]);

    const emitChange = (next: T) => {
        console.log(next)
        if (!isControlled) {
            setInternalValue(next);
        }

        onChange?.({
            target: { value: next },
        });
    };


    const onWorkletChange = (value: T) => {
        'worklet';
        currentReanimatedValue.value = value;
    };

    return {
        value: isControlled ? value : internalValue,
        emitChange,
        onWorkletChange,
        currentReanimatedValue,
        isControlled,
    };
}
